@class-prefix-nav-bar: ~'adm-nav-bar';

.@{class-prefix-nav-bar} {
  --height: 45px;
  --border-bottom: none;
  display: flex;
  align-items: center;
  height: var(--height);
  border-bottom: var(--border-bottom);
  padding: 0 12px;
  white-space: nowrap;

  &-left,
  &-right {
    flex: 1;
  }
  &-title {
    flex: auto;
    text-align: center;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &-back {
    display: flex;
    align-items: center;
    margin-right: 16px;
    padding: 6px 0;
    cursor: pointer;
    &-arrow {
      font-size: 24px;
      margin-right: 4px;
    }
  }

  &-left {
    font-size: var(--adm-font-size-7);
    display: flex;
    justify-content: flex-start;
    align-items: center;
  }

  &-title {
    justify-content: center;
    white-space: nowrap;
    font-size: var(--adm-font-size-10);
    padding: 0 12px;
  }

  &-right {
    text-align: right;
  }
}

@class-prefix-center-popup: ~'adm-center-popup';

.@{class-prefix-center-popup} {
  --background-color: var(
    --adm-center-popup-background-color,
    var(--adm-color-background)
  );
  --border-radius: var(--adm-center-popup-border-radius, 8px);
  --max-width: var(--adm-center-popup-max-width, 75vw);
  --min-width: var(--adm-center-popup-min-width, 280px);
  --z-index: var(--adm-center-popup-z-index, 1000);

  position: fixed;
  z-index: var(--z-index);

  .@{class-prefix-center-popup}-mask {
    z-index: 0;
  }
}

.@{class-prefix-center-popup}-wrap {
  position: fixed;
  z-index: 1;
  top: 50%;
  left: 50%;
  width: auto;
  min-width: var(--min-width);
  max-width: var(--max-width);
  transform: translate(-50%, -50%);
}

.@{class-prefix-center-popup}-body {
  background-color: var(--background-color);
  border-radius: var(--border-radius);
}

.@{class-prefix-center-popup}-close {
  position: absolute;
  z-index: 100;
  right: 8px;
  top: 8px;

  cursor: pointer;
  padding: 4px;
  font-size: 18px;
  color: var(--adm-color-weak);
}

@class-prefix-badge: ~'adm-badge';

.@{class-prefix-badge}-wrapper {
  display: inline-block;
  position: relative;
}

.@{class-prefix-badge} {
  display: inline-flex;
  vertical-align: middle;
  box-sizing: content-box;
  border-radius: 100px;
  background-color: var(--color);
  --right: 0;
  --top: 0;
  --color: var(--adm-badge-color, var(--adm-color-highlight));

  &-content {
    color: var(--adm-color-text-light-solid);
    box-sizing: border-box;
    min-width: 8px;
    padding: 1px 4px;
    font-size: var(--adm-font-size-1);
    line-height: 12px;
    white-space: nowrap;
    font-weight: normal;
    text-align: center;
  }

  &-fixed {
    position: absolute;
    right: var(--right);
    top: var(--top);
    transform: translate(50%, -50%);
  }

  &-dot {
    min-width: 10px;
    width: 10px;
    height: 10px;
    border-radius: 5px;
  }

  &-bordered {
    border: solid 1px var(--adm-color-text-light-solid);
  }
}

@class-prefix-divider: ~'adm-divider';

.@{class-prefix-divider} {
}

.adm-divider-horizontal {
  display: flex;
  align-items: center;
  margin: 16px 0;
  border-width: 0;
  border-color: var(--adm-color-border);
  border-style: solid;
  color: var(--adm-color-weak);
  font-size: 14px;
  .adm-divider-left&::before {
    max-width: 10%;
  }
  .adm-divider-right&::after {
    max-width: 10%;
  }
  &::after,
  &::before {
    flex: auto;
    display: block;
    content: '';
    border-style: inherit;
    border-color: inherit;
    border-width: 1px 0 0;
  }
  .adm-divider-content {
    flex: none;
    padding: 0 16px;
  }
}

.adm-divider-vertical {
  position: relative;
  top: -0.06em;
  display: inline-block;
  height: 0.9em;
  margin: 0 16px;
  vertical-align: middle;
  border-top: 0;
  border-left: 1px solid var(--adm-color-border);
}

//
// Jumbotron
// --------------------------------------------------


.jumbotron {
  padding-top:    @jumbotron-padding;
  padding-bottom: @jumbotron-padding;
  margin-bottom: @jumbotron-padding;
  color: @jumbotron-color;
  background-color: @jumbotron-bg;

  h1,
  .h1 {
    color: @jumbotron-heading-color;
  }

  p {
    margin-bottom: (@jumbotron-padding / 2);
    font-size: @jumbotron-font-size;
    font-weight: 200;
  }

  > hr {
    border-top-color: darken(@jumbotron-bg, 10%);
  }

  .container &,
  .container-fluid & {
    border-radius: @border-radius-large; // Only round corners at higher resolutions if contained in a container
    padding-left:  (@grid-gutter-width / 2);
    padding-right: (@grid-gutter-width / 2);
  }

  .container {
    max-width: 100%;
  }

  @media screen and (min-width: @screen-sm-min) {
    padding-top:    (@jumbotron-padding * 1.6);
    padding-bottom: (@jumbotron-padding * 1.6);

    .container &,
    .container-fluid & {
      padding-left:  (@jumbotron-padding * 2);
      padding-right: (@jumbotron-padding * 2);
    }

    h1,
    .h1 {
      font-size: @jumbotron-heading-font-size;
    }
  }
}

